module mux_4to1(
    input [3:0] obf_d,
    input [1:0] sel,
    output reg y
);

always @(obf_d or sel) begin
    case (sel)
        2'b00: y = obf_d[0];
        2'b01: y = obf_d[1];
        2'b10: y = obf_d[2];
        2'b11: y = obf_d[3];
        default: y = 1'b0;
    endcase
end

endmodule
